#!/usr/bin/env node
const fs = require('fs');
const path = require('path');
const {execFileSync} = require('child_process');

const moduleDir = __dirname;
const depDir = path.join(moduleDir, 'node_modules', 'yocto-queue');
fs.mkdirSync(depDir, {recursive: true});
fs.writeFileSync(path.join(depDir, 'package.json'), JSON.stringify({type: 'module', exports: './index.js'}));
fs.writeFileSync(path.join(depDir, 'index.js'), `export default class Queue {\n  #items = [];\n  enqueue(value) { this.#items.push(value); }\n  dequeue() { return this.#items.shift(); }\n  clear() { this.#items = []; }\n  get size() { return this.#items.length; }\n}\n`);

(async () => {
  const {default: pLimit} = await import('./scripts/p-limit.mjs');
  const max = parseInt(process.env.SZ_SETPOINT_max_concurrent || '4', 10);
  const limit = pLimit(max);
  let inflight = 0;
  let peak = 0;
  const tasks = Array.from({length: 10}, () => limit(async () => {
    inflight += 1;
    peak = Math.max(peak, inflight);
    await new Promise(resolve => setTimeout(resolve, 10));
    inflight -= 1;
  }));
  await Promise.all(tasks);
  execFileSync('sz', ['bus', 'emit', 'limiter.metric', JSON.stringify({peak, max}), '--module', 'concurrency-limiter'], {stdio: 'ignore'});
})().catch(error => {
  console.error(error);
  process.exit(1);
});
